#include <stdio.h>
#include <string.h>

int main(){
    int T; if(scanf("%d",&T)!=1) return 0; getchar();
    char line[101];
    for(int tc=0; tc<T; ++tc){
        if(!fgets(line, sizeof(line), stdin)) break;
        line[strcspn(line,"\n")] = '\0';
        int totalLen = strlen(line);
        char *token = strtok(line, " ");
        while(token){
            printf("%zu ", strlen(token));
            token = strtok(NULL, " ");
        }
        printf("%d\n", totalLen);
    }
    return 0;
}

