const fs = require('fs');
const lines = fs.readFileSync(0,'utf-8').split('\n');
let idx = 0;
const T = parseInt(lines[idx++].trim(),10);
let results = [];
for(let tc=0; tc<T; ++tc){
    const s = lines[idx++] || '';
    const totalLen = s.length;
    const parts = [];
    for(const w of s.split(' ')){
        if(w.length>0) parts.push(w.length);
    }
    parts.push(totalLen);
    results.push(parts.join(' '));
}
console.log(results.join('\n'));
